//! Controlled experiment: wall-legality filter wall-clock comparison.
//!
//! Three modes over IDENTICAL position sets (generated once, replayed):
//!   A  always-BFS   — `legal_walls_bruteforce` (baseline / control)
//!   B  writeup      — `legal_walls_writeup_bench` (faithful >=2-contacts filter)
//!   C  DSU          — `legal_walls` (curve-closing filter; QS_DSU_WALLS=1,
//!                     QS_SHADOW=0 so no shadow-tally overhead pollutes timing)
//!
//! Controls:
//!   * positions generated by seeded, wall-biased random playouts BEFORE any
//!     timing; every mode sees the same Vec in the same order;
//!   * a full correctness pass first: all three modes must return the SAME
//!     move set at every position (abort otherwise) — the experiment is void
//!     if any filter is wrong;
//!   * positions grouped by wall-density bucket; each (mode, bucket) batch is
//!     timed separately, so per-density curves come from batch timing, not
//!     per-call clocks;
//!   * warmup pass per mode before timed reps; REPS repetitions, median taken;
//!   * single-threaded throughout.
//!
//! Usage: legality_bench [n_positions] [w] [h] [walls]   (defaults 1_000_000 6 5 5)

use std::time::Instant;

use quoridor_solver::board::Board;
use quoridor_solver::movegen::{
    apply, legal_moves, legal_walls, legal_walls_bruteforce, legal_walls_writeup_bench,
};
use quoridor_solver::state::{Move, State};

const REPS: usize = 5;

struct Lcg(u64);
impl Lcg {
    fn next(&mut self) -> u64 {
        self.0 = self.0.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
        self.0 >> 16
    }
    fn below(&mut self, n: usize) -> usize {
        (self.next() % n as u64) as usize
    }
}

fn bucket(b: &Board, s: &State) -> usize {
    (2 * b.walls - s.walls_left[0] - s.walls_left[1]) as usize
}

fn main() {
    // Deterministic env for mode C; set before first movegen call (OnceLock).
    // SAFETY: single-threaded at this point (top of main, no threads spawned).
    unsafe {
        std::env::set_var("QS_DSU_WALLS", "1");
        std::env::set_var("QS_SHADOW", "0");
    }

    let args: Vec<String> = std::env::args().collect();
    let n_target: usize = args.get(1).and_then(|v| v.parse().ok()).unwrap_or(1_000_000);
    let w: u8 = args.get(2).and_then(|v| v.parse().ok()).unwrap_or(6);
    let h: u8 = args.get(3).and_then(|v| v.parse().ok()).unwrap_or(5);
    let walls: u8 = args.get(4).and_then(|v| v.parse().ok()).unwrap_or(5);
    let b = Board::new(w, h, walls);
    let nbuckets = (2 * walls) as usize + 1;

    // ---- generation (untimed): wall-biased seeded playouts ----
    eprintln!("[gen] target {n_target} positions on {w}x{h} W{walls} (wall-biased playouts)");
    let mut rng = Lcg(0xC0FFEE ^ ((w as u64) << 16 | (h as u64) << 8 | walls as u64));
    let mut by_bucket: Vec<Vec<State>> = vec![Vec::new(); nbuckets];
    let mut total = 0usize;
    while total < n_target {
        let mut s = b.initial();
        for _ply in 0..200 {
            if b.is_terminal(&s) {
                break;
            }
            if s.walls_left[s.turn as usize] > 0 {
                by_bucket[bucket(&b, &s)].push(s);
                total += 1;
                if total >= n_target {
                    break;
                }
            }
            let ms = legal_moves(&b, &s);
            if ms.is_empty() {
                break;
            }
            // Bias toward walls (65%) to populate the deep-density buckets.
            let wall_moves: Vec<&Move> = ms.iter().filter(|m| matches!(m, Move::Wall { .. })).collect();
            let mv = if !wall_moves.is_empty() && rng.below(100) < 65 {
                *wall_moves[rng.below(wall_moves.len())]
            } else {
                ms[rng.below(ms.len())]
            };
            s = apply(&b, &s, mv);
        }
    }
    for (k, v) in by_bucket.iter().enumerate() {
        if !v.is_empty() {
            eprintln!("[gen] bucket {k}: {} positions", v.len());
        }
    }

    // ---- correctness control: identical move sets across all three modes ----
    eprintln!("[verify] set-equality across modes at every position...");
    let key = |ms: &[Move]| -> Vec<(bool, u8, u8)> {
        let mut k: Vec<(bool, u8, u8)> = ms
            .iter()
            .filter_map(|m| match *m {
                Move::Wall { wc, wr, horiz } => Some((horiz, wc, wr)),
                _ => None,
            })
            .collect();
        k.sort_unstable();
        k
    };
    let mut verified = 0usize;
    for bs in &by_bucket {
        for s in bs {
            let a = key(&legal_walls_bruteforce(&b, s));
            let wmode = key(&legal_walls_writeup_bench(&b, s));
            let c = key(&legal_walls(&b, s));
            assert_eq!(
                a, wmode,
                "WRITEUP MODE DIVERGED at pawns={:?} h={:#x} v={:#x} wl={:?} turn={}",
                s.pawn, s.h_walls, s.v_walls, s.walls_left, s.turn
            );
            assert_eq!(
                a, c,
                "DSU MODE DIVERGED at pawns={:?} h={:#x} v={:#x} wl={:?} turn={}",
                s.pawn, s.h_walls, s.v_walls, s.walls_left, s.turn
            );
            verified += 1;
        }
    }
    eprintln!("[verify] {verified} positions, all three modes identical ✓");

    // ---- timed runs: (mode, bucket) batches, median of REPS ----
    type ModeFn = fn(&Board, &State) -> Vec<Move>;
    let modes: [(&str, ModeFn); 3] = [
        ("always-bfs", legal_walls_bruteforce as ModeFn),
        ("writeup", legal_walls_writeup_bench as ModeFn),
        ("dsu", legal_walls as ModeFn),
    ];

    println!("mode,bucket,positions,median_ns_per_pos,total_ms");
    let mut totals = [0f64; 3];
    for (mi, (name, f)) in modes.iter().enumerate() {
        // warmup over everything once
        for bs in &by_bucket {
            for s in bs {
                std::hint::black_box(f(&b, s).len());
            }
        }
        for (k, bs) in by_bucket.iter().enumerate() {
            if bs.is_empty() {
                continue;
            }
            let mut reps_ns: Vec<f64> = Vec::with_capacity(REPS);
            for _ in 0..REPS {
                let t0 = Instant::now();
                let mut sink = 0usize;
                for s in bs {
                    sink += std::hint::black_box(f(&b, s).len());
                }
                let dt = t0.elapsed().as_nanos() as f64;
                std::hint::black_box(sink);
                reps_ns.push(dt / bs.len() as f64);
            }
            reps_ns.sort_by(|a, c| a.partial_cmp(c).unwrap());
            let med = reps_ns[REPS / 2];
            totals[mi] += med * bs.len() as f64;
            println!("{name},{k},{},{:.1},{:.2}", bs.len(), med, med * bs.len() as f64 / 1e6);
        }
    }
    println!("# totals (weighted): always-bfs={:.1}ms writeup={:.1}ms dsu={:.1}ms", totals[0] / 1e6, totals[1] / 1e6, totals[2] / 1e6);
    println!("# speedup vs always-bfs: writeup={:.2}x dsu={:.2}x", totals[0] / totals[1], totals[0] / totals[2]);
    println!("# dsu vs writeup: {:.2}x", totals[1] / totals[2]);
}
